import {View, Text, Input, Button, Image} from '@tarojs/components'
import {useState} from 'react'
import Taro from '@tarojs/taro'
import {useAuth} from '@/contexts/AuthContext'
import {withRouteGuard, STORAGE_KEY_REDIRECT_PATH} from '@/components/RouteGuard'

function Login() {
  const {signInWithDriver} = useAuth()
  const [username, setUsername] = useState('')
  const [password, setPassword] = useState('')
  const [agreed, setAgreed] = useState(false)
  const [loading, setLoading] = useState(false)

  const handleLogin = async () => {
    if (!username.trim()) {
      Taro.showToast({
        title: '请输入账号',
        icon: 'none'
      })
      return
    }

    if (!password.trim()) {
      Taro.showToast({
        title: '请输入密码',
        icon: 'none'
      })
      return
    }

    if (!agreed) {
      Taro.showToast({
        title: '请先阅读并同意用户协议和隐私政策',
        icon: 'none'
      })
      return
    }

    setLoading(true)

    const {error} = await signInWithDriver(username, password)

    setLoading(false)

    if (error) {
      Taro.showToast({
        title: error.message || '账号或密码错误',
        icon: 'none'
      })
      return
    }

    Taro.showToast({
      title: '登录成功',
      icon: 'success'
    })

    // 登录成功后跳转
    setTimeout(() => {
      const redirectPath = Taro.getStorageSync(STORAGE_KEY_REDIRECT_PATH)
      Taro.removeStorageSync(STORAGE_KEY_REDIRECT_PATH)

      if (redirectPath && redirectPath !== '/pages/login/index') {
        // 检查是否是 TabBar 页面
        const isTabBar = redirectPath.includes('/pages/submit/index') || 
                        redirectPath.includes('/pages/records/index') || 
                        redirectPath.includes('/pages/profile/index')
        
        if (isTabBar) {
          Taro.switchTab({url: redirectPath})
        } else {
          Taro.navigateTo({url: redirectPath})
        }
      } else {
        Taro.switchTab({url: '/pages/submit/index'})
      }
    }, 500)
  }

  return (
    <View className="min-h-screen bg-gradient-subtle flex flex-col">
      <View className="flex-1 flex flex-col items-center justify-center px-8">
        <View className="w-full max-w-md">
          <View className="flex flex-col items-center mb-12">
            <Image
              src="data:image/png;base64,"
              className="w-36 h-36 rounded-2xl mb-6"
              mode="aspectFit"
            />
            <Text className="text-4xl font-bold text-foreground mb-2">司机报账系统</Text>
            <Text className="text-xl text-muted-foreground">广西马上国际货代专用</Text>
          </View>

          <View className="bg-card rounded-2xl p-8 shadow-elegant">
            <View className="flex flex-col space-y-6">
              <View className="flex flex-col space-y-2">
                <Text className="text-xl text-foreground font-medium">账号</Text>
                <View className="bg-input rounded-xl border border-border px-4 py-4">
                  <Input
                    className="w-full text-foreground text-xl"
                    placeholder="请输入账号"
                    value={username}
                    onInput={(e) => setUsername(e.detail.value)}
                  />
                </View>
              </View>

              <View className="flex flex-col space-y-2">
                <Text className="text-xl text-foreground font-medium">密码</Text>
                <View className="bg-input rounded-xl border border-border px-4 py-4">
                  <Input
                    className="w-full text-foreground text-xl"
                    placeholder="请输入密码"
                    password
                    value={password}
                    onInput={(e) => setPassword(e.detail.value)}
                  />
                </View>
              </View>

              <View className="flex flex-row items-center" onClick={() => setAgreed(!agreed)}>
                <View
                  className={`w-6 h-6 rounded border-2 flex items-center justify-center mr-3 flex-shrink-0 ${
                    agreed ? 'bg-primary border-primary' : 'bg-background border-border'
                  }`}>
                  {agreed && <View className="i-mdi-check text-primary-foreground text-xl" />}
                </View>
                <Text className="text-lg text-muted-foreground" style={{whiteSpace: 'nowrap'}}>
                  我已阅读并同意《用户协议》和《隐私政策》
                </Text>
              </View>

              <Button
                className="w-full bg-primary text-primary-foreground text-xl font-medium rounded-xl"
                onClick={handleLogin}
                disabled={loading}>
                <View className="py-4">
                  <Text>{loading ? '登录中...' : '登录'}</Text>
                </View>
              </Button>
            </View>
          </View>
        </View>
      </View>

      <View className="px-8 pb-8">
        <Text className="text-center text-xl text-muted-foreground">
          © 2026 司机报账系统
        </Text>
      </View>
    </View>
  )
}

export default withRouteGuard(Login)
